const body = $json.body || $json;
const transcript = String(body.transcript || '');
const lines = transcript.split(/\n|(?<=[.!?])\s+/).map(s => s.trim()).filter(Boolean);
const actions = [];
const decisions = [];
const risks = [];
const blockers = [];
function ownerFrom(line) { const m = line.match(/^([A-Z][a-z]+)\s+(will|owns|needs|should|has to|is responsible)/i) || line.match(/owner:?\s*([A-Z][a-z]+)/i); return m ? m[1] : 'Unassigned'; }
function dueFrom(line) { const m = line.match(/\b(by|before|due|on)\s+([A-Za-z]+day|tomorrow|next week|next [A-Za-z]+|[A-Z][a-z]+\s+\d{1,2})/i); return m ? m[2] : 'No date'; }
function priorityFrom(line) { const lower = line.toLowerCase(); if (/(blocker|risk|urgent|delay|missing|cannot|failed)/.test(lower)) return 'high'; if (/(should|needs|confirm|review)/.test(lower)) return 'medium'; return 'low'; }
for (const line of lines) { const lower = line.toLowerCase(); if (/^decision:|decision\b|decided\b/.test(lower)) decisions.push(line.replace(/^decision:\s*/i, '')); else if (/^risk:|risk\b|may delay|might delay|concern/.test(lower)) risks.push({ text: line.replace(/^risk:\s*/i, ''), severity: priorityFrom(line) }); else if (/^blocker:|blocker\b|blocked|missing|not shared|not confirmed/.test(lower)) blockers.push({ text: line.replace(/^blocker:\s*/i, ''), owner: ownerFrom(line), severity: priorityFrom(line) }); else if (/\b(will|owns|needs to|has to|should|responsible|prepare|send|finalize|update|confirm|share|complete)\b/i.test(line)) actions.push({ task: line, owner: ownerFrom(line), due: dueFrom(line), priority: priorityFrom(line), status: 'open' }); }
return [{ json: { meeting_title: body.meeting_title || 'Meeting notes', transcript, actions, decisions, risks, blockers, counts: { actions: actions.length, decisions: decisions.length, risks: risks.length, blockers: blockers.length } } }];
